import matplotlib; matplotlib.use("Agg"); import matplotlib.pyplot as plt; import numpy as np; fig, ax = plt.subplots(figsize=(5, 5)); ax.set_aspect("equal"); ax.axis("off"); ax.annotate("", xy=(5, 0), xytext=(-5, 0), arrowprops=dict(arrowstyle="<->", color="#1a1a1a", lw=1)); ax.annotate("", xy=(0, 5), xytext=(0, -5), arrowprops=dict(arrowstyle="<->", color="#1a1a1a", lw=1)); ax.text(4.8, -0.5, "x", fontsize=12); ax.text(-0.5, 4.8, "y", fontsize=12); x = np.linspace(-4, 4, 100); y1 = 0.6 * x + 1.5; y2 = 0.6 * x - 1.5; ax.plot(x, y1, color="#1a1a1a", linewidth=2); ax.plot(x, y2, color="#1a1a1a", linewidth=2); ax.set_xlim(-6, 6); ax.set_ylim(-6, 6); plt.savefig("out.png", dpi=150)